{
  "Name": "RoleManagement",
  "Key": "Account Management",
  "ResourceKey": "Account",
  "Script": "RoleManagement = {\n\tinit: async function (app, container) {\n\t\tapp = app || session.app;\n\t\tcontainer = container || $(\".component[name=RoleManagement]\");\n\t\tapi.addToMetaCache([\n\t\t\t{\n\t\t\t\t\"Name\": \"AppSecurity\",\n\t\t\t\t\"Types\": [\n\t\t\t\t\t[meta[AppSecurity/Role]]\n\t\t\t\t]\n\t\t\t}\n\t\t]);\n\t\tRoleManagement.setupRoleGrid(app, container);\n\t},\n\n\tsetupRoleGrid: async function (app, container) {\n\t\tvar config = {\n\t\t\tendpoint: \"AppSecurity/Role\",\n\t\t\todataAppend: \"?$filter=AppId eq \" + app.Id,\n\t\t\tsort: {\n\t\t\t\tfield: \"Name\",\n\t\t\t\tdir: \"asc\"\n\t\t\t}\n\t\t};\n\t\tvar ds = await model.getDatasource(config);\n\t\tvar roleGrid = new GridWidget(container, ds);\n\t\troleGrid.groupable = false;\n\t\troleGrid.pageable = false;\n\t\troleGrid.toolbar = [\n\t\t\t{\n\t\t\t\ttemplate: `<div class='btn-group btn-group-sm'>\n\t\t\t\t\t<button class='btn btn-primary' name='createRole'>\n\t\t\t\t\t\t<span class='k-icon k-i-plus'></span>[resource_displayname[NewRole]]\n\t\t\t\t\t</button>\n\t\t\t\t</div>`\n\t\t\t}\n\t\t];\n\t\troleGrid.columns = [{\n\t\t\tfield: \"Name\",\n\t\t\ttitle: \"[resource_shortdisplayname[Name]]\"\n\t\t}];\n\t\troleGrid.commands.push({\n\t\t\tname: \"[resource_displayname[save]]\",\n\t\t\ticon: 'k-i-save',\n\t\t\ttext: \"[resource_displayname[save]]\"\n\t\t});\n\t\troleGrid.commands.push({\n\t\t\tname: \"[resource_displayname[destroy]]\",\n\t\t\ticon: 'k-i-trash',\n\t\t\ttext: \"[resource_displayname[delete]]\"\n\t\t});\n\t\troleGrid.detailTemplate = $(\"[name=roleDetails]\").html();\n\t\troleGrid.detailExpand = function (e) {\n\t\t\tRoleManagement.expandRole(e, app, roleGrid);\n\t\t};\n\t\troleGrid.dataBound = function () {\n\t\t\t$(\"button[name=save]\", roleGrid.gridElement).off(\"click\").on(\"click\", async (e) => await RoleManagement.save(e, roleGrid));\n\t\t\t$(\"button[name=destroy]\", roleGrid.gridElement).off(\"click\").on(\"click\", async (e) => await RoleManagement.destroy(e, roleGrid));\n\t\t};\n\t\tawait roleGrid.init();\n\t\t$(\"button[name=createRole]\", roleGrid.gridElement).off(\"click\").on(\"click\", async (e) => await RoleManagement.createRole(e, app, roleGrid));\n\n\t\tawait loadComponent($('[name=roleUserManagementComponent]', container), 'RoleUserManagement');\n\t\tawait loadComponent($('[name=rolePrivManagementComponent]', container), 'RolePrivManagement');\n\t},\n\n\tsave: async function (e, grid) {\n\t\te.preventDefault();\n\t\tvar role = grid.dataItem($(e.currentTarget).closest(\"tr\"));\n\t\tawait role.save().then(() => { \n\t\t\tnotification.success(\"[resource_displayname[RoleSaved]]\"); \n\t\t}).catch((err) => {\n\t\t\terror(err);\n\t\t});\n\t},\n\n\tdestroy: async function (e, grid) {\n\t\te.preventDefault();\n\t\tvar row = $(e.currentTarget).closest(\"tr\");\n\t\tvar role = grid.dataItem(row);\n\t\tgrid.dataSource().remove(role);\n\t\tawait api.destroy(\"AppSecurity/Role(\" + role.Id + \")\").then(() => { \n\t\t\tnotification.success(\"[resource_displayname[roledeleted]]\"); \n\t\t}).catch((err) => {\n\t\t\terror(err);\n\t\t});\n\t},\n\n\texpandRole: async function (e, app, grid, container) {\n\t\tvar role = grid.dataItem(e.masterRow);\n\t\tvar container = $(e.detailRow);\n\n\t\tif (container.data(\"role-detail-initialised\")) {\n\t\t\treturn;\n\t\t}\n\t\tcontainer.data(\"role-detail-initialised\", true);\n\n\t\tvar replaced = container.html().replaceAll('{ID}', Guid());\n\t\tcontainer.html(replaced);\n\n\t\tawait RoleUserManagement.init(app, $(\"[name=userGrid]\", container), role);\n\t\tawait RolePrivManagement.init(app, $(\"[name=privGrid]\", container), role);\n\t},\n\n\tcreateRole: function (e, app, grid) {\n        var newRole = {\n            AppId: app.Id,\n            Name: \"[resource_displayname[newrole]]\",\n            Privs: \"\"\n        };\n\t\tvar args = {\n\t\t\tfields: [{\n\t\t\t\tfield: \"Name\",\n\t\t\t\ttitle: \"[resource_displayname[name]]\"\n\t\t\t}],\n\t\t\ttitle: \"[resource_displayname[newRole]]\",\n\t\t\tdata: newRole,\n\t\t\tconfirm: \"<span class='k-icon k-i-plus'></span>[resource_displayname[confirm]]\",\n\t\t\tclose: \"[resource_displayname[close]]\"\n\t\t};\n\t\tvar addRoleDialog = new EditorDialog(args);\n\t\taddRoleDialog.events.confirm = async function () {\n\t\t\tnewRole = addRoleDialog.data;//Remove all the kendo observable properties.\n\t\t\tawait api.add(\"AppSecurity/Role\", newRole).then(() => {\n                notification.success('[resource_displayname[RoleCreated]]');\n\t\t\t    grid.refresh();\n\t\t\t    addRoleDialog.events.close();\n            }).catch((err) => error(err));\n\t\t};\n\t\taddRoleDialog.init();\n\t}\n}\n",
